external_knowledge:
; Resources may include books, articles, movies, etc.; 
; Ratings are often given by users to express their opinions about a resource;
; Available copies refer to the number of physical or digital copies of a resource that are currently available for use.

sql:
SELECT 
  (SELECT COUNT(DISTINCT author_id) FROM resource_authors WHERE resource_id = 1) AS num_authors,
  (SELECT COUNT(DISTINCT subject_id) FROM resource_subjects WHERE resource_id = 1) AS num_subjects;

SELECT DISTINCT title
FROM resources
WHERE publication_year > 2020 AND copies_available > 5;

